#include <iostream>
#include <string>

class Label
{
private:
    std::string m_text{};
    int m_id{};

public:
    Label(const std::string& text, int id)
        : m_text{ text }, m_id{ id }
    {
    }

    Label& operator=(const Label& other)
    {
        if (this == &other)
            return *this;

        m_text = other.m_text;
        m_id = other.m_id;
        return *this;
    }

    void print() const
    {
        std::cout << '[' << m_id << "] " << m_text << '\n';
    }
};

int main()
{
    std::string text1{};
    int id1{};
    std::string text2{};
    int id2{};

    std::getline(std::cin, text1);
    std::cin >> id1;
    std::cin.ignore();
    std::getline(std::cin, text2);
    std::cin >> id2;

    Label a{ text1, id1 };
    Label b{ text2, id2 };

    a.print();
    b.print();

    a = b;

    a.print();
    b.print();

    return 0;
}

