#include <iostream>

class Counter
{
private:
    int m_value{};

public:
    Counter(int v) : m_value{ v } {}

    Counter& operator=(const Counter& other)
    {
        if (this == &other)
            return *this;

        m_value = other.m_value;
        return *this;
    }

    void print() const
    {
        std::cout << m_value << '\n';
    }
};

int main()
{
    int va{};
    int vb{};
    int vc{};
    std::cin >> va >> vb >> vc;

    Counter a{ va };
    Counter b{ vb };
    Counter c{ vc };

    a.print();
    b.print();
    c.print();

    std::cout << '\n';

    a = b = c;

    a.print();
    b.print();
    c.print();

    return 0;
}
